import { useEffect, useState } from "react";
import "./styles.css"
function Mainweatherpage() {
    let [cityinput, changeinput] = useState("")
    let [dataafterclick, changedata] = useState({})
    let fullweatherdata = JSON.parse(localStorage.getItem("defaultweatherdata"))
    console.log(fullweatherdata)
    function function1(e) { 
        changeinput(e.target.value)
    }
    async function apicall() {
        try {
        let weatherdata  = await fetch(`https://api.openweathermap.org/data/2.5/weather?q=${cityinput[0].toUpperCase() + cityinput.slice(1)}&appid=d782528f491fa0b8359a25fc07739daa&units=metric`)
        let updatedweather = await weatherdata.json()
        let alldata2 = {maindata: updatedweather.main, city: updatedweather.name, weathertype: updatedweather.weather[0]}
        let arrback = await fetch("http://localhost:5000/weathersession", {
            method: "POST",
            headers: {"Content-Type":"application/json"},
            credentials: "include",
            body: JSON.stringify({citysessionback: alldata2})
        })
         let temporary =  await arrback.json()
         changedata(temporary)
         localStorage.setItem("bool", true)
         changebool(true) //send bool to the server and make it a session in order for the results to properly render
         console.log(dataafterclick)
        //render arrback so the weather data could be rendered from input and not from the login button that sets london as a default city
        } catch(err) {
            console.log(err)
        }
    }
    return<>
  <div className="controls">
    <input
      value={cityinput}
      onChange={(e) => function1(e)}
      type="text"
      placeholder="Enter city (e.g. London)"
    />
    <button onClick={() => apicall()}>Look at the weather</button>  
  </div>
  {fullweatherdata ? 
  <div>
  <div className="weather-main">
    <div className="city">
      <p className="label">My location</p>
      <p className="name">{dataafterclick.city }</p>
    </div>
  <div className="temp">
      <div className="degrees">{  dataafterclick.maindata.temp }°</div>
      <div className="type">{  dataafterclick.weathertype.main}</div>
    </div>
  </div>

  <div className="stats" role="list" aria-label="Weather details">
    <div className="stat" role="listitem">
      <div className="val">{ Math.floor(dataafterclick.maindata.temp_max) }°</div>
      <div className="k">High</div>
    </div>
    <div className="stat" role="listitem">
      <div className="val">{checkbool ? Math.floor(dataafterclick.maindata.temp_min) : Math.floor(fullweatherdata.alldata.maindata.temp_min)}°</div>
      <div className="k">Low</div>
    </div>
    <div className="stat" role="listitem">
      <div className="val">{Math.floor(fullweatherdata.alldata.maindata.feels_like) || "—"}°</div>
      <div className="k">Feels like</div>
    </div>
    <div className="stat" role="listitem">
      <div className="val">{fullweatherdata.alldata.maindata.humidity || "—"}%</div>
      <div className="k">Humidity</div>
    </div>
  </div>

  <div className="weather-footer">
    <span>Data provided by your API</span>
    <span style={{opacity:0.85}}>Updated just now</span>
  </div>
    </div>
    :
  ""
}
    </>
    //add another layer of html to render arrback if the default london data has been rendered once already
}
export default Mainweatherpage
